INSERT INTO products (id, name, description, image_url, sizes, price, stock, category_id, brand, colors, image_urls, specifications) VALUES
(1, 'Oxford Cotton Shirt', 'Smart regular-fit shirt for office and weekend styling, tailored from premium long-staple cotton.', 'https://images.unsplash.com/photo-1602810318383-e386cc2a3ccf?auto=format&fit=crop&w=900&q=80', 'S,M,L,XL', 1499.00, 150, 1, 'Luxe Classic', 'White,Blue,Soft Pink', 'https://images.unsplash.com/photo-1602810318383-e386cc2a3ccf?auto=format&fit=crop&w=900&q=80,https://images.unsplash.com/photo-1596755094514-f87e34085b2c?auto=format&fit=crop&w=900&q=80,https://images.unsplash.com/photo-1589310243389-96a5483213a8?auto=format&fit=crop&w=900&q=80', 'Material: 100% Long-Staple Cotton\nFit: Regular Fit\nCollar: Button-Down Collar\nSleeve: Long Sleeves\nPattern: Solid\nCare: Machine wash warm, iron medium'),
(2, 'Urban Bomber Jacket', 'Lightweight jacket with ribbed cuffs, premium zippers, and a clean streetwear finish.', 'https://images.unsplash.com/photo-1520975916090-3105956dac38?auto=format&fit=crop&w=900&q=80', 'M,L,XL', 3499.00, 120, 1, 'StreetElite', 'Black,Olive Green,Navy', 'https://images.unsplash.com/photo-1520975916090-3105956dac38?auto=format&fit=crop&w=900&q=80,https://images.unsplash.com/photo-1495105787522-5334e3ffa0ef?auto=format&fit=crop&w=900&q=80', 'Material: Water-Resistant Nylon Shell\nLining: Satin Polyester\nFit: Athletic Bomber Fit\nPockets: 2 side zipper pockets, 1 sleeve zip pouch\nWeight: Medium-weight\nCare: Dry clean recommended'),
(3, 'Slim Stretch Denim', 'Dark wash jeans with flexible stretch fabric for maximum comfort and modern tapered fit.', 'https://images.unsplash.com/photo-1542272604-787c3835535d?auto=format&fit=crop&w=900&q=80', '30,32,34,36', 2299.00, 180, 1, 'DenimCraft', 'Dark Indigo,Charcoal,Stone Wash', 'https://images.unsplash.com/photo-1542272604-787c3835535d?auto=format&fit=crop&w=900&q=80,https://images.unsplash.com/photo-1541099649105-f69ad21f3246?auto=format&fit=crop&w=900&q=80', 'Material: 98% Cotton, 2% Elastane Lycra\nFit: Slim Fit\nRise: Mid-Rise\nClosure: Button fly with branded shank button\nWash: Dark Indigo indigo-dyed\nCare: Wash inside out with similar colors'),
(4, 'Floral Midi Dress', 'Flowing midi dress with soft floral print, relaxed silhouette, and premium georgette lining.', 'https://images.unsplash.com/photo-1612336307429-8a898d10e223?auto=format&fit=crop&w=900&q=80', 'XS,S,M,L', 2799.00, 110, 2, 'Aura London', 'Floral Crimson,Pastel Lavender', 'https://images.unsplash.com/photo-1612336307429-8a898d10e223?auto=format&fit=crop&w=900&q=80,https://images.unsplash.com/photo-1595777457583-95e059d581b8?auto=format&fit=crop&w=900&q=80', 'Material: 100% Recycled Polyester Georgette\nLining: Soft Viscose Lining\nFit: Fit and Flare\nLength: Midi\nDetail: Tiered skirt, smocked back panel\nCare: Hand wash cold, line dry'),
(5, 'Satin Evening Top', 'Elegant satin top with a polished cowl neck drape for sophisticated evening looks.', 'https://images.unsplash.com/photo-1551163943-3f6a855d1153?auto=format&fit=crop&w=900&q=80', 'S,M,L', 1799.00, 140, 2, 'Atelier Gold', 'Champagne Gold,Emerald Green,Jet Black', 'https://images.unsplash.com/photo-1551163943-3f6a855d1153?auto=format&fit=crop&w=900&q=80,https://images.unsplash.com/photo-1583743814966-8936f5b7be1a?auto=format&fit=crop&w=900&q=80', 'Material: Premium Silk Satin (95% Silk, 5% Spandex)\nFit: Semi-fitted\nNeckline: Draped Cowl Neck\nSleeves: Sleeveless\nCare: Dry clean or cold delicate wash in mesh bag'),
(6, 'Tailored Blazer Dress', 'Structured double-breasted blazer dress with sharp lapels and a premium tailored finish.', 'https://images.unsplash.com/photo-1485968579580-b6d095142e6e?auto=format&fit=crop&w=900&q=80', 'S,M,L,XL', 4299.00, 100, 2, 'Atelier Gold', 'Ivory White,Midnight Black', 'https://images.unsplash.com/photo-1485968579580-b6d095142e6e?auto=format&fit=crop&w=900&q=80,https://images.unsplash.com/photo-1544022613-e87ca75a784a?auto=format&fit=crop&w=900&q=80', 'Material: Premium Wool Blend (60% Polyester, 40% Wool)\nLining: 100% Jacquard Silk Lining\nFit: Tailored Structured Fit\nButtons: Embossed Gold Buttons\nCare: Dry clean only'),
(7, 'Classic Gold Chronograph', 'Water-resistant stainless steel watch with metallic gold dial and premium leather strap.', 'https://images.unsplash.com/photo-1522312346375-d1a52e2b99b3?auto=format&fit=crop&w=900&q=80', 'One Size', 12999.00, 150, 1, 'Atelier Gold', 'Gold,Black', 'https://images.unsplash.com/photo-1522312346375-d1a52e2b99b3?auto=format&fit=crop&w=900&q=80,https://images.unsplash.com/photo-1547996160-81dfa63595aa?auto=format&fit=crop&w=900&q=80', 'Type: Chronograph\nCase: 42mm Stainless Steel\nDial: 24K Gold-plated\nMovement: Swiss Quartz\nStrap: Genuine Italian Leather\nWater Resistance: 50m (5 ATM)\nWarranty: 2 Years'),
(8, 'Silk Wrap Midi Skirt', 'A beautifully draped midi skirt made from luxury mulberry silk with an adjustable tie waist.', 'https://images.unsplash.com/photo-1583496661160-fb488b2c1a82?auto=format&fit=crop&w=900&q=80', 'XS,S,M,L', 3899.00, 120, 2, 'Aura London', 'Champagne,Emerald,Black', 'https://images.unsplash.com/photo-1583496661160-fb488b2c1a82?auto=format&fit=crop&w=900&q=80,https://images.unsplash.com/photo-1577900232427-18219b9166a0?auto=format&fit=crop&w=900&q=80', 'Material: 100% Mulberry Silk\nLength: Midi\nFit: Adjustable Wrap Fit\nPattern: Solid Satin\nCare: Dry clean or cold hand wash only'),
(9, 'Tailored Double-Breasted Suit', 'A premium Italian wool-blend suit featuring sharp notch lapels and structured shoulder construction.', 'https://images.unsplash.com/photo-1593032465175-481ac7f401a0?auto=format&fit=crop&w=900&q=80', '46,48,50,52,54', 14999.00, 80, 1, 'Luxe Classic', 'Midnight Black,Charcoal Grey', 'https://images.unsplash.com/photo-1593032465175-481ac7f401a0?auto=format&fit=crop&w=900&q=80,https://images.unsplash.com/photo-1594938298603-c8148c4dae35?auto=format&fit=crop&w=900&q=80', 'Material: 70% Wool, 30% Silk Blend\nLining: Full Bemberg Silk Lining\nLapel: Notch Lapel\nFit: Slim Fit Tailored\nClosure: Double-Breasted 6-Button\nCare: Professional Dry Clean Only'),
(10, 'Velvet Cocktail Gown', 'An exquisite floor-length evening gown crafted from plush silk velvet with an elegant side slit.', 'https://images.unsplash.com/photo-1566174053879-31528523f8ae?auto=format&fit=crop&w=900&q=80', 'S,M,L,XL', 8999.00, 95, 2, 'Atelier Gold', 'Burgundy,Royal Navy,Emerald', 'https://images.unsplash.com/photo-1566174053879-31528523f8ae?auto=format&fit=crop&w=900&q=80,https://images.unsplash.com/photo-1595777457583-95e059d581b8?auto=format&fit=crop&w=900&q=80', 'Material: 80% Rayon, 20% Silk Velvet\nLength: Floor Length Gown\nFit: Sculpted Bodycon Fit\nDetails: Off-shoulder neckline, side slit\nCare: Dry clean only'),
(11, 'Leather Chelsea Boots', 'Handcrafted Italian leather boots with elasticated side panels and a stacked wooden heel.', 'https://images.unsplash.com/photo-1618244972963-dbee1a7edc95?auto=format&fit=crop&w=900&q=80', '8,9,10,11', 5499.00, 110, 1, 'DenimCraft', 'Tan Brown,Jet Black', 'https://images.unsplash.com/photo-1618244972963-dbee1a7edc95?auto=format&fit=crop&w=900&q=80,https://images.unsplash.com/photo-1608256246200-53e635b5b65f?auto=format&fit=crop&w=900&q=80', 'Material: Hand-burnished Calfskin Leather\nLining: Leather Lined Insole\nSole: Stacked Wood & Rubber Outer Sole\nConstruction: Goodyear Welted\nHeel: 1.2 inches'),
(12, 'Designer Sunglasses', 'Premium tortoiseshell acetate frames featuring UV400 protective polarized lenses and gold metal branding.', 'https://images.unsplash.com/photo-1511499767150-a48a237f0083?auto=format&fit=crop&w=900&q=80', 'One Size', 2499.00, 200, 2, 'Aura London', 'Tortoiseshell,Midnight Black', 'https://images.unsplash.com/photo-1511499767150-a48a237f0083?auto=format&fit=crop&w=900&q=80,https://images.unsplash.com/photo-1572635196237-14b3f281503f?auto=format&fit=crop&w=900&q=80', 'Frame Material: High-quality Acetate\nLenses: Polarized UV400 Protection\nBrand hardware: Gold plated signature logo\nInclude: Leather hard case and cleaning cloth');
